UPDATE alevel_source_file
SET status = 0,
    update_time = #{updateTime}
WHERE source_file_name = #{sourceFileName}
  AND alevel_source_file_id != #{keepSourceFileId}
  AND status = 1
  AND delete_flag = '1'

